function textOn(hex) { const h = hex.replace('#', ''); const r = parseInt(h.slice(0, 2), 16), g = parseInt(h.slice(2, 4), 16), b = parseInt(h.slice(4, 6), 16); return (0.299 * r + 0.587 * g + 0.114 * b) > 150 ? "#0a1020" : "#ffffff"; }

function normSig(x,k,a) {
 return ((x-a)**k)/((x-a)**k+(1-(x-a))**k)
}

/**
 * Calculates the generalized p-mean of an array of numbers.
 * @param {number[]} arr - Array of positive numbers.
 * @param {number} p - The power mean parameter (e.g., -Infinity, 0, 1, 2, Infinity).
 * @returns {number} The generalized p-mean.
 */
function generalizedMean(arr, p = 1) {
    if (!arr || arr.length === 0) return NaN;
    
    const n = arr.length;

    // Edge case: p = Infinity (returns the maximum value)
    if (p === Infinity) {
        return Math.max(...arr);
    }

    // Edge case: p = -Infinity (returns the minimum value)
    if (p === -Infinity) {
        return Math.min(...arr);
    }

    // Edge case: p = 0 (geometric mean)
    if (p === 0) {
        const product = arr.reduce((acc, val) => acc * val, 1);
        return Math.pow(product, 1 / n);
    }

    // Standard p-mean calculation: ( (1/n) * sum(x^p) ) ^ (1/p)
    const sum = arr.reduce((acc, val) => acc + Math.pow(val, p), 0);
    return Math.pow(sum / n, 1 / p);
}

/* ===== SCORING (TUNABLE) ===== */
const RATE = { R0: 0.55, R1: 0.972, gamma: 2.4, Tb: 0.66, GATE: 18 };
const FPPG_FLOOR_PERFECT = 150; /* Total FPPG required for a 17-0 finish. Below this, max is 16-1. */
const CORE = [["P1", "P1"], ["P2", "P1"], ["P3", "P1"]];
const RESULT_ORDER = ["P1","P2","P3"];
const P1COEF = 1.025709
const P2COEF = 1.042256
const P3COEF = 1.042392
/* Each starter's era-relative percentile (erp, 0..1) is baked into the data.
   Team rating = equal-weighted mean of all 7 starters (no position is weighted more).
   Balance gate: the weakest required starter caps the ceiling, so 17-0 needs an
   elite season at EVERY spot. Win curve is non-linear (steep at the top).
   FPPG_FLOOR_PERFECT: an additional raw-points gate for the 17-0 finish. */
function projectRecord(roster) {
    var overalls = []
    overalls.push([roster.P1.atk,roster.P1.mid,roster.P1.def]);
    overalls.push([roster.P2.atk,roster.P2.mid,roster.P2.def]);
    overalls.push([roster.P3.atk,roster.P3.mid,roster.P3.def]);

    const p1Score = generalizedMean(overalls[0])*P1COEF
    const p2Score = generalizedMean(overalls[1])*P2COEF
    const p3Score = generalizedMean(overalls[2])*P3COEF

    const ovrScore = generalizedMean([p1Score,p2Score,p3Score],3)
    var points = ovrScore > 97.99 ? 165 : (ovrScore >= 90 ? (65*(165*normSig((ovrScore/100),0.5,-0.02))/37.424550133)-120.425724452 : (ovrScore >= 80 ? (35.8887797754/18.4475182497)*(165*normSig((ovrScore/100),0.2,-0.09))-128.575702638 : (ovrScore >= 70 ? (30/4.45445217992)*(165*normSig((ovrScore/100),0.1,0.64))-444.66159468 : (ovrScore >= 40 ? (20/34.0573143501)*(165*normSig((ovrScore/100),0.3,-0.28))-38.9023002987 : (ovrScore >= 0 ? (15/53.6630250684)*(165*normSig((ovrScore/100),1.8,-0.6))-31.1211420125 : 0)))))
    points = points*(75/165)
    return [ovrScore, points];
}
function gradeFor(w) {
    if (w > 97.99) return ["S", "The Perfect Season", "#00FFF9"];
    if (w >= 96.5) return ["A+", "Shift Circuit Dynasty", "#7CFF71"]; if (w >= 92.5) return ["A", "Shift Circuit MVP", "#7CFF71"]; if (w >= 89.5) return ["A-", "Shift Worlds Champion", "#7CFF71"];
    if (w >= 86.5) return ["B+", "2x Shift Event Champion", "#00D7FF"]; if (w >= 82.5) return ["B", "Shift Worlds Finalist", "#00D7FF"];if (w >= 79.5) return ["B-", "Shift Worlds Contender", "#00D7FF"];
    if (w >= 76.5) return ["C+", "Shift Event Champion", "#FF7A00"]; if (w >= 72.5) return ["C", "Shift Event Finalist", "#FF7A00"]; if (w >= 69.5) return ["C-", "Shift Worlds Qualifier", "#FF7A00"];
    if (w >= 66.5) return ["D+", "Shift Event Regular", "#FF6482"]; if (w >= 62.5) return ["D", "Shift Event Participant", "#FF6482"]; if (w >= 59.5) return ["D-", "Occassional Shift Participant", "#FF6482"];
    return ["F", "Total Bum", "#ce3b3b"];
}

