function placeSlotInCategory(pos, cat) { for (const sid of CAT_SLOTS[cat]) { if (!state.roster[sid] && SLOTS.find(s => s.id === sid).elig.includes(pos)) return sid; } return null; }
function destSlotInCategory(source, cat) { for (const sid of CAT_SLOTS[cat]) { if (!state.roster[sid] && validDest(source, sid)) return sid; } for (const sid of CAT_SLOTS[cat]) { if (state.roster[sid] && validDest(source, sid)) return sid; } return null; }
function openSheet(mode, arg) {
    let player, source = null;
    if (mode === "place") { player = arg; state.selected = player; state.moveSource = null; $("sheet-title").textContent = `${player.n} — Confirm Placement`; }
    else { source = arg; player = state.roster[source]; state.moveSource = source; state.selected = null; $("sheet-title").textContent = `Move ${player.n}`; }
    const body = $("sheet-body"); body.innerHTML = "";
    CAT_ORDER.forEach(cat => {
        const elig = catEligible(player.p, cat); let active = false, sub = "";
        if (!elig) sub = "";
        else if (mode === "place") { if (placeSlotInCategory(player.p, cat)) active = true; else sub = "Unfilled"; }
        else { if (destSlotInCategory(source, cat)) active = true; else sub = "—"; }
        const btn = document.createElement("button"); btn.className = "pos-btn" + (active ? " active" : " disabled");
        if (active) btn.style.cssText = `background:${CAT_COLOR[cat]};color:#000000`;
        if (!active) btn.style.cssText = `background:${CAT_COLORDARK[cat]};color:#ffffff`;
        btn.innerHTML = `<span>${CAT_LABEL[cat]}</span>${sub ? `<span class="pb-sub">${sub}</span>` : ""}`;
        if (active) btn.onclick = () => { if (mode === "place") { const slot = placeSlotInCategory(player.p, cat); closeSheet(true); placePlayer(slot); } else { const dest = destSlotInCategory(source, cat); closeSheet(true); doMove(source, dest); } };
        body.appendChild(btn);
    });
    $("pos-sheet").classList.add("open");
}
function closeSheet(keep) { $("pos-sheet").classList.remove("open"); if (!keep) { state.selected = null; state.moveSource = null; if (isDraft()) renderPool(); } }

const SORT_OPTS = {
    ALL: [["gpg", "GPG"], ["apg", "APG"], ["sapg", "SAPG"], ["shpg", "SHPG"]]
};
function updateSortOptions() { const o = SORT_OPTS[state.filter] || SORT_OPTS.ALL; state.sort = "gpg"; $("sort").innerHTML = o.map(([v, l]) => `<option value="${v}">${l}</option>`).join(""); }
function renderPool() {
    let players = GAMEDATA.pools[state.spin.team + "|" + state.spin.year].slice();
    const picked = new Set(Object.values(state.roster).filter(Boolean).map(r => r.n));
    players = players.filter(p => !picked.has(p.n));
    document.getElementById('tag-team').innerText = state.spin.team;
    document.getElementById('tag-year').innerText = state.spin.year;
    if (state.filter !== "ALL") players = players.filter(p => p.p === state.filter);
    if (state.q) players = players.filter(p => p.n.toLowerCase().includes(state.q.toLowerCase()));
    const s = state.sort; players.sort((a, b) => (b[s] ?? -1) - (a[s] ?? -1));
    $("avail-count").textContent = players.length + " players available";
    const pool = $("pool"); pool.innerHTML = "";
    players.forEach(p => {
        const teamID = p.season + "_" + p.team
        const imgURL = "/src/165/logosshift/" + teamID + ".webp"
        const teamCOL = TEAMS.get(teamID)
        var pos = ""
        if (p.p === "P1") {
            pos = "<p1>" + p.p + "</p1>"
        } else if (p.p === "P2") {
            pos = "<p2>" + p.p + "</p2>"
        }  else if (p.p === "P3") {
            pos = "<p3>" + p.p + "</p3>"
        } 
        var subtext = pos + " · " + p.season + " · " + p.team
        
        const can = eligibleSlotExists(p.p); const card = document.createElement("div");
        card.className = "pcard" + (state.selected === p ? " sel" : "") + (can ? "" : " disabled");
        card.innerHTML = `<div style="display:flex; width:100%"><div class="pc-icon" style="border: 2px solid ${teamCOL}; background-color:color-mix(in oklab, ${teamCOL} 15%, #0C0C0C 85%)"><img class="pc-image" src="${imgURL}"></div>
        <div style="padding-top: 3px;"><div class="pc-name">${p.n}</div><div class="pc-sub">${subtext}</div></div><div class="pc-stats">${statsHTML(p)}</div>`;
        if (can) card.onclick = () => isMobile() ? openSheet("place", p) : selectPlayer(p); pool.appendChild(card);
    });
}
function statsHTML(p) {
    const S = (v, k, cls = "") => `<div class="stat ${cls}"><div class="v">${v}</div><div class="k">${k}</div></div>`; let h = "";
    h = S(p.gpg.toFixed(2), "GOAL/G") + S(p.apg.toFixed(2), "ASST/G", "cut3") + S(p.sapg.toFixed(2), "SAVE/G", "cut2") + S(p.shpg.toFixed(2), "SHOT/G", "cut"); return h;
}
function selectPlayer(p) {
    state.moving = null; state.selected = (state.selected === p) ? null : p; $("place-hint").style.display = state.selected ? "inline" : "none";
    if (state.selected) { $("banner").className = "banner"; $("banner").textContent = `Placing ${state.selected.n} — click a highlighted slot`; } else bannerReset(true);
    renderPool(); refreshSlots();
}
function placePlayer(slotId) {
    const p = state.selected; if (!p) return;
    state.roster[slotId] = { ...p}; state.selected = null; $("place-hint").style.display = "none";
    if (state.round >= 3) { showResult(); return; }
    state.round++; $("round-num").textContent = state.round; state.filter = "ALL"; state.q = ""; state.sort = "gpg"; $("search").value = "";
    document.querySelectorAll(".fbtn").forEach(b => b.classList.toggle("active", b.dataset.f === "ALL")); showSpinView();
    showSpinView();
}
